resources.string:
var visible by remember { mutableStateOf(false) }
LaunchedEffect(Unit) { visible = true }

Box(
    modifier = %1$s
) {
    // Your content here
}

// Component with canimation entry animation
%1$s

// The component uses Modifier.canimation() internally:
// modifier.canimation(visible = entryVisible, effect = Canimation.XXX.YYY)

@Composable
fun MyScreen() {
    var visible by remember { mutableStateOf(false) }
    LaunchedEffect(Unit) { visible = true }

    CanimationProvider(policy = CanimationPolicy.AlwaysFull) {
        Box(
            modifier = %1$s
        ) {
            Text("Hello, Canimation!")
        }
    }
}

@Composable
fun MyScreen() {
    // The component uses Modifier.canimation() internally
    // for its entry animation
    CanimationProvider(policy = CanimationPolicy.AlwaysFull) {
        %1$s
    }
}

fun fade(
 from: Float = 0f,
 to: Float = 1f,
): CanimationEffect

fun scale(
 from: Float = 0.92f,
 to: Float = 1f,
): CanimationEffect

fun pop(
 from: Float = 0.8f,
 to: Float = 1f,
): CanimationEffect

// Simple fade up
Modifier.canimation(
    visible = isVisible,
    effect = Canimation.Fade.Up,
)

// Combine effects
Modifier.canimation(
    visible = isVisible,
    effect = Canimation.Scale.Pop + Canimation.Fade.In,
)

LazyColumn {
    itemsIndexed(items) { index, item ->
        Card(
            Modifier.canimationEnter(
                visible = true,
                preset = CanimationPreset.FadeUp,
            )
        ) { Text(item.name) }
    }
}

CanimationVisibility(
    visible = showContent,
    enterPreset = CanimationPreset.BounceIn,
) {
    Text("Hello, Canimation!")
}

// Always play full animations regardless of system setting
CanimationProvider(
    policy = CanimationPolicy.AlwaysFull,
) {
    // All canimation calls inside use Full motion
    Box(Modifier.canimation(visible, Canimation.Fade.Up)) {
        Text("Animated content")
    }
}

// Single primitives CanimationEffect.fade() // alpha: 0 → 1 CanimationEffect.slideUp(16.dp) // offsetY: 16dp → 0dp CanimationEffect.scale(0.9f) // scale: 0.9 → 1.0 CanimationEffect.rotate(-15f) // rotation: -15° → 0°
// Combine freely with + val custom = CanimationEffect.fade() + CanimationEffect.slideUp(24.dp) + CanimationEffect.scale(0.8f) + CanimationEffect.duration(400)
Modifier.canimation(visible = show, effect = custom)

// Atoms compose into Molecules
val molecule = CanimationEffect.fade() + CanimationEffect.slideUp()
// equivalent to: Canimation.Fade.Up

// Molecules compose into Organisms  
val organism = Canimation.Fade.Up + CanimationEffect.scale(0.8f) + CanimationEffect.rotate(-10f)
// Custom complex animation!

// Same code runs on all platforms
Modifier.canimation(visible = show, effect = Canimation.Fade.Up)
// Works on: Android, iOS, Desktop, Web JS, Web WasmJs

object Stagger {
 const val Quick = 40 // ms
 const val Normal = 70 // ms
 const val Slow = 120 // ms
 const val Relaxed = 200 // ms
}

fun fade(
 from: Float = 0f,
 to: Float = 1f,
): CanimationEffect

fun scale(
 from: Float = 0.92f,
 to: Float = 1f,
): CanimationEffect

fun pop(
 from: Float = 0.8f,
 to: Float = 1f,
): CanimationEffect

// Simple fade up
Modifier.canimation(
    visible = isVisible,
    effect = Canimation.Fade.Up,
)

// Combine effects
Modifier.canimation(
    visible = isVisible,
    effect = Canimation.Scale.Pop + Canimation.Fade.In,
)

LazyColumn {
    itemsIndexed(items) { index, item ->
        Card(
            Modifier.canimationEnter(
                visible = true,
                preset = CanimationPreset.FadeUp,
            )
        ) { Text(item.name) }
    }
}

CanimationVisibility(
    visible = showContent,
    enterPreset = CanimationPreset.BounceIn,
) {
    Text("Hello, Canimation!")
}

// Always play full animations regardless of system setting
CanimationProvider(
    policy = CanimationPolicy.AlwaysFull,
) {
    // All canimation calls inside use Full motion
    Box(Modifier.canimation(visible, Canimation.Fade.Up)) {
        Text("Animated content")
    }
}

items.forEachIndexed { i, item ->
    LaunchedEffect(Unit) {
        delay(i * Canimation.Stagger.Normal.toLong())
        visible = true
    }
    Box(Modifier.canimation(visible, Canimation.Fade.Up)) {
        Text(item)
    }
}
